const treinadores=[{id:"thais-prando",nome:"Thaís Prando",foto:"../images/treinadores/thais-prando.jpg",genero:"feminino",faixaEtaria:"31-50",modalidade:"corrida",nivel:"intermediario",acompanhamento:"intermediario",perfil:"lesao",regioes:["florianopolis","online"],url:"../pages/treinadores/thais-prando.html"},{id:"guto-fernandes",nome:"Guto Fernandes",foto:"../images/treinadores/guto-fernandes.jpg",genero:"masculino",faixaEtaria:"30-menos",modalidade:"corrida",nivel:"avancado",acompanhamento:"intermediario",perfil:"alto-rendimento",regioes:["florianopolis"],url:"../pages/treinadores/guto-fernandes.html"},{id:"bruno-jeremias",nome:"Bruno Jeremias",foto:"../images/treinadores/bruno-jeremias.jpg",genero:"masculino",faixaEtaria:"30-menos",modalidade:"corrida-trilha",nivel:"intermediario",acompanhamento:"intermediario",perfil:"saude",regioes:["florianopolis","online"],url:"../pages/treinadores/bruno-jeremias.html"},{id:"elinai-freitas",nome:"Elinai Freitas",foto:"../images/treinadores/elinai-freitas.jpg",genero:"feminino",faixaEtaria:"31-50",modalidade:"corrida",nivel:"iniciante",acompanhamento:"intermediario",perfil:"iniciante",regioes:["florianopolis"],url:"../pages/treinadores/elinai-freitas.html"},{id:"jessica-rodrigues",nome:"Jéssica Rodrigues",foto:"../images/treinadores/jessica-rodrigues.jpg",genero:"feminino",faixaEtaria:"30-menos",modalidade:"triathlon",nivel:"iniciante",acompanhamento:"intermediario",perfil:"saude",regioes:["online"],url:"../pages/treinadores/jessica-rodrigues.html"},{id:"denis-santana",nome:"Denis Santana",foto:"../images/treinadores/denis-santana.jpg",genero:"masculino",faixaEtaria:"30-menos",modalidade:"triathlon",nivel:"avancado",acompanhamento:"intermediario",perfil:"performance",regioes:["sao-paulo"],url:"../pages/treinadores/denis-santana.html"}];const pesos={regiao:8,modalidade:5,perfil:3,nivel:2,acompanhamento:2,faixaEtaria:1,genero:1};const pontuacaoMaxima=Object.values(pesos).reduce((a,b)=>a+b,0);let respostasUsuario={regiao:null,faixaEtaria:null,genero:null,modalidade:null,tempo5k:null,acompanhamento:null,perfil:null};let etapaAtual=1;const totalEtapas=7;const quizContainer=document.getElementById("quiz-container");const progressBar=document.getElementById("progress-bar");const etapaIndicator=document.getElementById("etapa-indicator");const resultadosContainer=document.getElementById("resultados-container");document.addEventListener("DOMContentLoaded",()=>{mostrarEtapa(1);atualizarProgressBar()});function mostrarEtapa(etapa){document.querySelectorAll(".etapa").forEach(el=>{el.style.display="none"});const etapaElement=document.getElementById(`etapa-${etapa}`);if(etapaElement){etapaElement.style.display="block"}etapaAtual=etapa;atualizarProgressBar();if(etapaIndicator){etapaIndicator.textContent=`${etapa}/${totalEtapas}`}}function atualizarProgressBar(){if(progressBar){const progresso=etapaAtual/totalEtapas*100;progressBar.style.width=`${progresso}%`}}function proximaEtapa(){if(etapaAtual<totalEtapas){mostrarEtapa(etapaAtual+1)}else{calcularResultados()}}function etapaAnterior(){if(etapaAtual>1){mostrarEtapa(etapaAtual-1)}}function selecionarRegiao(regiao){respostasUsuario.regiao=regiao;document.querySelectorAll(".opcao-regiao").forEach(el=>{el.classList.remove("selecionado")});document.querySelector(`.opcao-regiao[data-valor="${regiao}"]`).classList.add("selecionado");setTimeout(proximaEtapa,300)}function selecionarFaixaEtaria(faixaEtaria){respostasUsuario.faixaEtaria=faixaEtaria;document.querySelectorAll(".opcao-faixa-etaria").forEach(el=>{el.classList.remove("selecionado")});document.querySelector(`.opcao-faixa-etaria[data-valor="${faixaEtaria}"]`).classList.add("selecionado");setTimeout(proximaEtapa,300)}function selecionarGenero(genero){respostasUsuario.genero=genero;document.querySelectorAll(".opcao-genero").forEach(el=>{el.classList.remove("selecionado")});document.querySelector(`.opcao-genero[data-valor="${genero}"]`).classList.add("selecionado");setTimeout(proximaEtapa,300)}function selecionarModalidade(modalidade){respostasUsuario.modalidade=modalidade;document.querySelectorAll(".opcao-modalidade").forEach(el=>{el.classList.remove("selecionado")});document.querySelector(`.opcao-modalidade[data-valor="${modalidade}"]`).classList.add("selecionado");setTimeout(proximaEtapa,300)}function selecionarTempo5k(tempo){let nivel;if(tempo==="mais27"){nivel="iniciante"}else if(tempo==="entre20e27"){nivel="intermediario"}else if(tempo==="menos20"){nivel="avancado"}respostasUsuario.tempo5k=tempo;respostasUsuario.nivel=nivel;document.querySelectorAll(".opcao-tempo").forEach(el=>{el.classList.remove("selecionado")});document.querySelector(`.opcao-tempo[data-valor="${tempo}"]`).classList.add("selecionado");setTimeout(proximaEtapa,300)}function selecionarAcompanhamento(estilo){respostasUsuario.acompanhamento=estilo;document.querySelectorAll(".opcao-acompanhamento").forEach(el=>{el.classList.remove("selecionado")});document.querySelector(`.opcao-acompanhamento[data-valor="${estilo}"]`).classList.add("selecionado");setTimeout(proximaEtapa,300)}function selecionarPerfil(perfil){respostasUsuario.perfil=perfil;document.querySelectorAll(".opcao-perfil").forEach(el=>{el.classList.remove("selecionado")});document.querySelector(`.opcao-perfil[data-valor="${perfil}"]`).classList.add("selecionado");setTimeout(calcularResultados,300)}function calcularPontuacao(treinador){let pontuacao=0;if(respostasUsuario.regiao&&treinador.regioes&&treinador.regioes.includes(respostasUsuario.regiao)){pontuacao+=pesos.regiao}if(respostasUsuario.genero==="prefiro-nao-informar"||treinador.genero===respostasUsuario.genero){pontuacao+=pesos.genero}if(treinador.faixaEtaria===respostasUsuario.faixaEtaria){pontuacao+=pesos.faixaEtaria}if(respostasUsuario.modalidade==="indeciso"){pontuacao+=pesos.modalidade}else if(respostasUsuario.modalidade==="corrida-trilha"){if(treinador.modalidade==="corrida-trilha"){pontuacao+=pesos.modalidade+2}else if(treinador.modalidade==="corrida"){pontuacao+=pesos.modalidade-1}else if(treinador.modalidade==="triathlon"){pontuacao+=pesos.modalidade-2}}else if(respostasUsuario.modalidade==="corrida"){if(treinador.modalidade==="corrida"||treinador.modalidade==="corrida-trilha"){pontuacao+=pesos.modalidade}}else if(respostasUsuario.modalidade==="triathlon"){if(treinador.modalidade==="triathlon"){pontuacao+=pesos.modalidade}}if(treinador.nivel===respostasUsuario.nivel){pontuacao+=pesos.nivel}if(treinador.acompanhamento===respostasUsuario.acompanhamento){pontuacao+=pesos.acompanhamento}if(treinador.perfil===respostasUsuario.perfil){pontuacao+=pesos.perfil}return pontuacao}function calcularResultados(){quizContainer.style.display="none";const pontuacoes=treinadores.map(treinador=>{const pontos=calcularPontuacao(treinador);const percentual=Math.round(pontos/pontuacaoMaxima*100);return{treinador:treinador,pontos:pontos,percentual:percentual}});pontuacoes.sort((a,b)=>b.pontos-a.pontos);const maxPontos=pontuacoes[0].pontos;const empatados=pontuacoes.filter(p=>p.pontos===maxPontos);let resultados;if(empatados.length>1){resultados=empatados}else{resultados=[pontuacoes[0]]}let resultadosHTML=`\n        <h2>Seu treinador ideal!</h2>\n        <p class="resultado-subtitulo">Baseado nas suas respostas, encontramos ${resultados.length>1?"estes treinadores":"este treinador"} com alta compatibilidade:</p>\n        <div class="resultados-grid">\n    `;resultados.forEach(resultado=>{resultadosHTML+=`\n            <div class="resultado-card">\n                <div class="resultado-pontuacao-tag">${resultado.pontos} pontos de ${pontuacaoMaxima} possíveis</div>\n                <img src="${resultado.treinador.foto}" alt="${resultado.treinador.nome}" class="resultado-foto">\n                <h3 class="resultado-nome">${resultado.treinador.nome}</h3>\n                <p class="resultado-especialidade">${formatarModalidade(resultado.treinador.modalidade)}</p>\n                <p class="resultado-nivel">${formatarNivel(resultado.treinador.nivel)}</p>\n                <div class="resultado-acoes">\n                    <a href="${resultado.treinador.url}" class="btn-ver-perfil">Ver perfil completo</a>\n                    <a href="${resultado.treinador.url}#planos-valores" class="btn-treinar">Treinar com ${resultado.treinador.nome.split(" ")[0]}</a>\n                </div>\n            </div>\n        `});resultadosHTML+=`\n        </div>\n        <div class="resultado-acoes-finais">\n            <button onclick="reiniciarQuiz()" class="btn-reiniciar">Refazer o quiz</button>\n            <a href="../index.html#treinadores" class="btn-todos-treinadores">Ver todos os treinadores</a>\n        </div>\n    `;resultadosContainer.innerHTML=resultadosHTML;resultadosContainer.style.display="block";window.scrollTo(0,0)}function reiniciarQuiz(){respostasUsuario={regiao:null,faixaEtaria:null,genero:null,modalidade:null,tempo5k:null,acompanhamento:null,perfil:null};document.querySelectorAll(".opcao-selecionavel").forEach(el=>{el.classList.remove("selecionado")});if(document.getElementById("data-nascimento")){document.getElementById("data-nascimento").value=""}resultadosContainer.style.display="none";quizContainer.style.display="block";mostrarEtapa(1)}function formatarModalidade(modalidade){const formatacao={corrida:"Corrida",triathlon:"Triathlon","corrida-trilha":"Corrida em Trilha"};return formatacao[modalidade]||modalidade}function formatarNivel(nivel){const formatacao={iniciante:"Especialista em Iniciantes",intermediario:"Especialista em Nível Intermediário",avancado:"Especialista em Nível Avançado"};return formatacao[nivel]||nivel}